/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across all channels
 * (email, SMS, webhook).
 *
 * DECISION CHANGE (Session 9): This model was originally designed for email-only
 * notifications (Session 3). With SMS support added in Session 8, the email-only
 * assumption is no longer valid. The model now supports per-channel preferences
 * for email, SMS, and webhook. Existing email-only preferences remain backward
 * compatible — the sms and webhook fields are optional and default to enabled
 * with all categories when absent (opt-out model).
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are batched and sent.
 * - 'immediate': each notification is sent as it occurs
 * - 'daily': notifications are batched into a daily digest
 * - 'weekly': notifications are batched into a weekly digest
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification settings.
 */
export interface SmsPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification settings.
 */
export interface WebhookPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Full notification preferences for a user.
 *
 * The email field is always present (backward compatible with original model).
 * The sms and webhook fields are optional — when absent, those channels are
 * treated as enabled with all categories (opt-out model).
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms?: SmsPreferences;
  webhook?: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences (userId is set separately).
 */
export interface CreatePreferencesInput {
  email?: Partial<EmailPreferences>;
