parameters.new_string:
/**
 * Check whether email notifications are allowed for a user and notification type.
 * If no preferences exist, notifications are allowed by default (opt-out model).
 *
 * @deprecated Use isChannelAllowed(userId, 'email', notificationType) instead.
 */
isEmailAllowed(userId: string, notificationType: NotificationType): boolean {
  return this.isChannelAllowed(userId, 'email', notificationType);
}

/**
 * Check whether notifications on a given channel are allowed for a user.
 * If no preferences exist, notifications are allowed by default (opt-out model).
 * If preferences exist but the specific channel has no settings, that channel
 * is allowed by default (backward compatible — existing email-only preferences
 * don't block SMS/webhook).
 */
isChannelAllowed(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
  const prefs = this.preferencesRepo.findByUserId(userId);
  if (!prefs) {
    return true;
  }

  switch (channel) {
    case 'email': {
      if (!prefs.email.enabled) return false;
      return prefs.email.subscribedCategories.includes(notificationType);
    }
    case 'sms': {
      if (!prefs.sms) return true;
      if (!prefs.sms.enabled) return false;
      return prefs.sms.subscribedCategories.includes(notificationType);
    }
    case 'webhook': {
      if (!prefs.webhook) return true;
      if (!prefs.webhook.enabled) return false;
      return prefs.webhook.subscribedCategories.includes(notificationType);
    }
    default:
      return true;
  }
}

